import{_ as t,o as a,c as o,ai as i}from"./chunks/framework.2e-g_11C.js";const p=JSON.parse('{"title":"Automation Quickstart","description":"","frontmatter":{},"headers":[],"relativePath":"automation-quickstart.md","filePath":"automation-quickstart.md"}'),r={name:"automation-quickstart.md"};function n(s,e,c,l,u,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="automation-quickstart" tabindex="-1">Automation Quickstart <a class="header-anchor" href="#automation-quickstart" aria-label="Permalink to “Automation Quickstart”">​</a></h1><p>Get started using flows, triggers, operations, and the data chain to create custom event-driven data processing.</p><p>This guide covers creating a simple flow that sends a notification when a post is created.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to “Before You Start”">​</a></h2><p>You will need a Likha ERP project with a <code>posts</code> collection containing at least <code>title</code> and <code>content</code> fields.</p><h2 id="create-a-flow" tabindex="-1">Create a Flow <a class="header-anchor" href="#create-a-flow" aria-label="Permalink to “Create a Flow”">​</a></h2><p>Navigate to the Flows section in the Settings module. Click the add button in the page header and name the new flow &quot;Post Created&quot;.</p><h2 id="configure-a-trigger" tabindex="-1">Configure a Trigger <a class="header-anchor" href="#configure-a-trigger" aria-label="Permalink to “Configure a Trigger”">​</a></h2><p>Click on the trigger configuration area. Select &quot;Event Hook&quot; as the trigger type and select &quot;Action (Non-Blocking)&quot;. This allows the flow to respond to events without interrupting the transaction.</p><p>Select <code>items.create</code> as the scope, and then check the &quot;Posts&quot; collection. This means the flow will be triggered when a post is created.</p><h2 id="configure-an-operation" tabindex="-1">Configure an Operation <a class="header-anchor" href="#configure-an-operation" aria-label="Permalink to “Configure an Operation”">​</a></h2><p>Click the add button on the trigger panel to create an operation. Give it the name &quot;Notify Post Created&quot; (the key will be auto-generated).</p><p>Select the &quot;Send Notification&quot; operation type. Fill in the &quot;User&quot; field with the UUID of your user, which can be found in the user directory. Under &quot;Permissions&quot;, select &quot;From Trigger&quot;, which will cause the operation to have the same permissions as those from the trigger.</p><p>Fill in the &quot;Subject&quot; and &quot;Message&quot; fields as desired, leaving &quot;Collection&quot; and &quot;Item&quot; blank.</p><p>When finished, save the flow.</p><p>Now, when you create a post, the user you entered will be notified.</p>',16)])])}const f=t(r,[["render",n]]);export{p as __pageData,f as default};
